import{_ as e,o as a,c as r,a1 as d}from"./chunks/framework.BX4nIuL2.js";const u=JSON.parse('{"title":"Auto CAD","description":"","frontmatter":{},"headers":[],"relativePath":"courses/fab-course/doc/6laser_cutter/AutoCAD.md","filePath":"courses/fab-course/doc/6laser_cutter/AutoCAD.md"}'),o={name:"courses/fab-course/doc/6laser_cutter/AutoCAD.md"};function i(n,t,l,s,c,g){return a(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="auto-cad" tabindex="-1">Auto CAD <a class="header-anchor" href="#auto-cad" aria-label="Permalink to &quot;Auto CAD&quot;">​</a></h1><h2 id="_1-what-is-auto-cad" tabindex="-1">1. What is Auto CAD <a class="header-anchor" href="#_1-what-is-auto-cad" aria-label="Permalink to &quot;1. What is Auto CAD&quot;">​</a></h2><p>AutoCAD® is computer-aided design (CAD) software that architects, engineers, and construction professionals rely on to create precise 2D and 3D drawings.</p><p>Draft, annotate, and design 2D geometry and 3D models with solids, surfaces, and mesh objects Automate tasks such as comparing drawings, addings blocks, creating schedules, and more Customize with add-on apps and APIs Reference from <a href="https://www.autodesk.com/products/autocad/overview?plc=ACDIST&amp;term=1-YEAR&amp;support=ADVANCED&amp;quantity=1" target="_blank" rel="noreferrer">AutoCAD</a></p><p><img src="https://gitlab.com/picbed/bed/uploads/05f7c9b4c1ff67357f62df448f8970fe/620e0b2bed607cdfc94715d6f6b15b59.jpg" alt=""> Reference from <a href="https://blog.51cto.com/jettcai/2286072" target="_blank" rel="noreferrer">51cto</a></p><h2 id="_2-how-to-use-it" tabindex="-1">2. How to use it <a class="header-anchor" href="#_2-how-to-use-it" aria-label="Permalink to &quot;2. How to use it&quot;">​</a></h2><p>The UI of autoCAD2018 <img src="https://gitlab.com/picbed/bed/uploads/38a5adf67eed15762f3d698b96283c52/WX20200422-055038_2x.png" alt=""> Some official learn information for reference:<a href="https://knowledge.autodesk.com/support/autocad/learn?sort=score" target="_blank" rel="noreferrer">link</a></p><p>We can use graphic commands or Command Line to use the function we need.If we want to use command line we need remember AutoCAD shortcuts &amp; hotkey which you can reference part 3 &quot;3. AutoCAD shortcuts &amp; hotkey guide&quot; <img src="https://gitlab.com/picbed/bed/uploads/ad6b7611fe7d4cc746a651061354af76/command.png" alt=""></p><h2 id="_3-autocad-shortcuts-hotkey-guide" tabindex="-1">3. AutoCAD shortcuts &amp; hotkey guide <a class="header-anchor" href="#_3-autocad-shortcuts-hotkey-guide" aria-label="Permalink to &quot;3. AutoCAD shortcuts &amp; hotkey guide&quot;">​</a></h2><table tabindex="0"><thead><tr><th>type</th><th>Hotkey</th><th style="text-align:right;">Function</th></tr></thead><tbody><tr><td>Drawing</td><td></td><td style="text-align:right;"></td></tr><tr><td>Drawing</td><td>A</td><td style="text-align:right;">Draw an arc</td></tr><tr><td>Drawing</td><td>AR</td><td style="text-align:right;">Opens array dialogue box</td></tr><tr><td>Drawing</td><td>F</td><td style="text-align:right;">FILLET / Rounds and fillets the edges of objects</td></tr><tr><td>Drawing</td><td>H</td><td style="text-align:right;">HATCH / Fills an enclosed area or selected objects with a hatch pattern, solid fill, or gradient fill</td></tr><tr><td>Drawing</td><td>I</td><td style="text-align:right;">INSERT / Inserts a block or drawing into the current drawing</td></tr><tr><td>Drawing</td><td>L</td><td style="text-align:right;">LINE / Creates straight line segments</td></tr><tr><td>Drawing</td><td>MI</td><td style="text-align:right;">MIRROR / Creates a mirrored copy of selected objects</td></tr><tr><td>Drawing</td><td>O</td><td style="text-align:right;">OFFSET / Creates concentric circles, parallel lines, and parallel curves</td></tr><tr><td>Drawing</td><td>TA</td><td style="text-align:right;">TEXTALIGN / Aligns multiple text objects vertically, horizontally, or obliquely</td></tr><tr><td>Drawing</td><td>TB</td><td style="text-align:right;">TABLE / Creates an empty table object</td></tr><tr><td>Editting</td><td></td><td style="text-align:right;"></td></tr><tr><td>Editting</td><td>B</td><td style="text-align:right;">BLOCK / Creates a block definition from selected objects</td></tr><tr><td>Editting</td><td>X</td><td style="text-align:right;">EXPLODE / Breaks a compound object into its component objects.</td></tr><tr><td>Editting</td><td>Ctrl+A</td><td style="text-align:right;">Select all objects</td></tr><tr><td>Editting</td><td>Ctrl+X</td><td style="text-align:right;"></td></tr><tr><td>Editting</td><td>Ctrl+C</td><td style="text-align:right;"></td></tr><tr><td>Editting</td><td>Ctrl+V</td><td style="text-align:right;"></td></tr><tr><td>Editting</td><td>Ctrl+Z</td><td style="text-align:right;"></td></tr><tr><td>Editting</td><td>DI</td><td style="text-align:right;">DIST / Measures the distance and angle between two points</td></tr><tr><td>Editting</td><td>E</td><td style="text-align:right;">ERASE / Removes objects from a drawing</td></tr><tr><td>Editting</td><td>EX</td><td style="text-align:right;">EXTEND / Extends objects to meet the edges of other objects</td></tr><tr><td>Editting</td><td>M</td><td style="text-align:right;">MOVE / Moves objects a specified distance in a specified direction</td></tr><tr><td>Editting</td><td>MA</td><td style="text-align:right;">MATCHPROP / Applies the properties of a selected object to other objects</td></tr><tr><td>Manage</td><td></td><td style="text-align:right;"></td></tr><tr><td>Manage</td><td>Ctrl+N</td><td style="text-align:right;">New Drawing</td></tr><tr><td>Manage</td><td>Ctrl+O</td><td style="text-align:right;">Open drawing</td></tr><tr><td>Manage</td><td>Ctrl+S</td><td style="text-align:right;">Save drawing</td></tr><tr><td>Manage</td><td>RE</td><td style="text-align:right;">REGEN / Regenerates the entire drawing from the current viewport</td></tr><tr><td>Manage</td><td>REA</td><td style="text-align:right;">REGENALL / Regenerates the drawing and refreshes all viewports</td></tr><tr><td>Manage</td><td>Ctrl+A</td><td style="text-align:right;">Select all objects</td></tr><tr><td>Manage</td><td>Ctrl+X</td><td style="text-align:right;">Cut object</td></tr><tr><td>Manage</td><td>Ctrl+C</td><td style="text-align:right;">Copy object</td></tr><tr><td>Manage</td><td>Ctrl+V</td><td style="text-align:right;">Paste object</td></tr><tr><td>Manage</td><td>Ctrl+Z</td><td style="text-align:right;">Undo last action</td></tr><tr><td>Manage</td><td>ESC</td><td style="text-align:right;">Cancel current command</td></tr><tr><td>Manage</td><td>D</td><td style="text-align:right;">DIMSTYLE / Creates and modifies dimension styles</td></tr><tr><td>Manage</td><td>G</td><td style="text-align:right;">GROUP / Creates and manages saved sets of objects called groups</td></tr><tr><td>Manage</td><td>LA</td><td style="text-align:right;">LAYER / Manages layers and layer properties</td></tr></tbody></table><p><img src="https://gitlab.com/picbed/bed/uploads/a7fb299fc8c8eb4e76f6962fc28afe00/SHORTCUT.png" alt=""></p><ul><li><p>More detail from <a href="https://www.autodesk.com/shortcuts/autocad" target="_blank" rel="noreferrer">AutoCAD</a></p></li><li><p><a href="https://knowledge.autodesk.com/support/autocad/learn-explore/caas/sfdcarticles/sfdcarticles/Creating-a-keyboard-shortcut-in-AutoCAD.html" target="_blank" rel="noreferrer">How to create custom command shortcuts in AutoCAD</a></p></li></ul><h2 id="_4-install" tabindex="-1">4. Install <a class="header-anchor" href="#_4-install" aria-label="Permalink to &quot;4. Install&quot;">​</a></h2><p>Reference here to install <a href="http://www.downza.cn/soft/270697.html" target="_blank" rel="noreferrer">AutoCAD 2018</a> , for another version of CAD ,the method is similar.</p><h2 id="_5-input-fusion-data-to-autocad" tabindex="-1">5. Input fusion data to AutoCAD <a class="header-anchor" href="#_5-input-fusion-data-to-autocad" aria-label="Permalink to &quot;5. Input fusion data to AutoCAD&quot;">​</a></h2><ul><li>Create standard 2D drawings from your 3D geometry by entering the DRAWING workspace. See the Drawings section of the help for more information.</li><li>Choice Drawing&gt;from design</li><li>In creating drawing,we can determine the size and other information , I choice IOS standard, unit is mmsheet size A4,etc</li><li>Output from dxf formate and then open in AutoCAD</li></ul><h2 id="_6-reference" tabindex="-1">6. Reference <a class="header-anchor" href="#_6-reference" aria-label="Permalink to &quot;6. Reference&quot;">​</a></h2><ul><li><a href="https://www.autodesk.com/products/autocad/overview?plc=ACDIST&amp;term=1-YEAR&amp;support=ADVANCED&amp;quantity=1" target="_blank" rel="noreferrer">AutoCAD</a></li><li><a href="https://www.autodesk.com/shortcuts/autocad" target="_blank" rel="noreferrer">AutoCAD hotkey</a></li><li><a href="https://blog.51cto.com/jettcai/2286072" target="_blank" rel="noreferrer">different autocad from 51cto</a></li><li><a href="https://knowledge.autodesk.com/support/autocad/learn?sort=score" target="_blank" rel="noreferrer">Official learn information</a></li><li><a href="http://www.caxa.com/" target="_blank" rel="noreferrer">CAXA</a></li></ul>',18)])])}const f=e(o,[["render",i]]);export{u as __pageData,f as default};
